import{_ as n,o as s,c as o,a as r}from"./chunks/framework.8tiMeCK-.js";const h=JSON.parse('{"title":"2.4  NETLINK_ROUTE 消息：不只是路由","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_networking/ch02_4.md","filePath":"notes/linux_kernel_networking/ch02_4.md","lastUpdated":null}'),i={name:"notes/linux_kernel_networking/ch02_4.md"};function t(l,e,a,d,c,p){return s(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="_2-4-netlink-route-消息-不只是路由" tabindex="-1">2.4 NETLINK_ROUTE 消息：不只是路由 <a class="header-anchor" href="#_2-4-netlink-route-消息-不只是路由" aria-label="Permalink to &quot;2.4  NETLINK_ROUTE 消息：不只是路由&quot;">​</a></h1><p>上一节我们在 Generic Netlink 的机制里打转，把消息头、TLV、验证策略这些东西拆了个底朝天。现在地基打好了，是时候把视线收回到网络子系统本身，看看那些「老资格」的 Netlink 协议家族是怎么工作的。</p><p>其中最重量级的，当属 <code>NETLINK_ROUTE</code>。</p><p>别被名字骗了——虽然它叫 Route Netlink，但这哥们儿管的远不止路由表那么简单。它是整个网络配置的「总管家」，手里攥着网卡、地址、邻居表、流量控制这一大摊子事儿。</p><p>具体来说，<code>NETLINK_ROUTE</code> 的消息家族（Family）按功能划分成了好几支人马：</p><ul><li><strong>LINK</strong>：管网络接口的，比如 <code>eth0</code> 的启动、关闭、改名。</li><li><strong>ADDR</strong>：管 IP 地址的添加和删除。</li><li><strong>ROUTE</strong>：这才是真正的路由消息，管 FIB（转发信息库）。</li><li><strong>NEIGH</strong>：管邻居子系统，也就是 ARP 和 ND（Neighbor Discovery）表。</li><li><strong>RULE</strong>：管策略路由规则的。</li><li><strong>QDISC</strong>、<strong>TCLASS</strong>、<strong>ACTION</strong>：这一块是 QoS（流量控制）相关的，排队规则、流量分类、动作处理都在这儿。</li><li><strong>NEIGHTBL</strong>：邻居表本身的配置。</li><li><strong>ADDRLABEL</strong>：地址标签（通常用于 IPv6）。</li></ul><h3 id="crud-与消息类型的映射" tabindex="-1">CRUD 与消息类型的映射 <a class="header-anchor" href="#crud-与消息类型的映射" aria-label="Permalink to &quot;CRUD 与消息类型的映射&quot;">​</a></h3><p>不管是上面哪个家族，它们的消息类型设计都遵循一套非常直观的 CRUD（增删改查）逻辑。</p><p>对于大多数对象（比如路由 Route、地址 Addr、邻居 Neigh），都只有三种操作：</p><ol><li><strong>创建</strong>：对应 <code>RTM_NEWXXX</code> 消息（如 <code>RTM_NEWROUTE</code>）。</li><li><strong>删除</strong>：对应 <code>RTM_DELXXX</code> 消息（如 <code>RTM_DELROUTE</code>）。</li><li><strong>查询</strong>：对应 <code>RTM_GETXXX</code> 消息（如 <code>RTM_GETROUTE</code>）。</li></ol><p>这就像标准的数据库操作。</p><p>但有一个特例，那就是 <strong>LINK（网络接口）</strong>。网卡的配置有时候比单纯的「增删查」要复杂一点——你可能只想修改某个参数（比如 MTU），而不是把网卡删了再重建。所以，除了上面那三个标配消息，Link 家族多了一个<strong>修改</strong>专用的消息：<code>RTM_SETLINK</code>。</p><h3 id="当操作出错时-nlmsgerr-结构" tabindex="-1">当操作出错时：nlmsgerr 结构 <a class="header-anchor" href="#当操作出错时-nlmsgerr-结构" aria-label="Permalink to &quot;当操作出错时：nlmsgerr 结构&quot;">​</a></h3><p>我们在写用户态程序时，最怕的不是拒绝，而是沉默——你发一个请求过去，内核没反应，你根本不知道是没收到还是处理挂了。</p><p>Netlink 协议的设计者显然考虑到了这一点。他们设计了一套标准的报错机制，无论你是通过标准 Netlink 还是 Generic Netlink 通信，这套机制都通用。</p><p>这一切都封装在一个 <code>nlmsgerr</code> 结构体里：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nlmsgerr {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        error;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           /* 负数表示标准 errno 错误码，0 表示成功/ACK */</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nlmsghdr msg;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        /* 触发错误的原始请求消息头 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>你可以把这个结构体想象成一张「退件单」。</p><p>当你发送的消息有问题——比如 <code>nlmsg_type</code> 填了一个内核不认识的值——内核不会干瞪眼，它会给你回发一个 Netlink 消息。这个回包的消息头类型是 <code>NLMSG_ERROR</code>，紧接着就是上面的 <code>nlmsgerr</code> 结构体。</p><p>这时候会发生一个有趣的操作：</p><p>如果 <code>error</code> 字段不为 0（比如是 <code>-EOPNOTSUPP</code>），这张「退件单」的后面还会附上你<strong>最初发出去的那条消息的头部</strong>（也就是 <code>msg</code> 字段）。</p><p><strong>为什么要这么做？</strong></p><p>想想看，你在处理多线程或异步通信的时候，可能同时发出了好几个请求。当其中一个错误返回时，你怎么知道是哪个请求炸了？</p><p>内核很贴心地把你发的请求头原封不动贴回来，你只需要比对这个包头里的序列号，就能立刻对号入座，找到是哪次操作出错了。</p><p>图 2-4 展示了这个报错消息的内存布局：</p><blockquote><p><strong>[图 2-4：Netlink 错误消息布局]</strong></p><ul><li><strong>Netlink Header (type = NLMSG_ERROR)</strong></li><li><strong>Error Code (int)</strong> : 比如 <code>-EINVAL</code> 或 <code>-EOPNOTSUPP</code></li><li><strong>Original Request Header</strong> : 原始请求的 <code>nlmsghdr</code>（仅当 error != 0 时存在）</li><li><strong>Original Payload</strong> : (注：通常代码里只附带 header，不附带整个 payload，除非有特殊调试需求)</li></ul></blockquote><h3 id="ack-机制的微妙之处" tabindex="-1">ACK 机制的微妙之处 <a class="header-anchor" href="#ack-机制的微妙之处" aria-label="Permalink to &quot;ACK 机制的微妙之处&quot;">​</a></h3><p>有时候我发请求，不是为了修改配置，就是为了确认「你收到了没」。这时候就需要 ACK（确认应答）机制。</p><p>请求 ACK 的方式很简单：在发送消息的 Flag 里加上 <code>NLM_F_ACK</code>。</p><p>内核收到后，如果处理没问题，就会回给你一个 <code>NLMSG_ERROR</code> 类型的消息。但注意，这里有个反直觉的设计：</p><p><strong>即使是成功（ACK），内核回的消息类型也是 <code>NLMSG_ERROR</code>。</strong></p><p>区别在于 <code>nlmsgerr</code> 结构里的 <code>error</code> 字段：</p><ul><li>如果 <code>error</code> 为 <strong>0</strong>，这就不是一张「退件单」，而是一张「签收单」。</li><li>这时候，<code>msg</code> 字段（原始请求头）<strong>不会</strong>被附在回包里——因为成功了，内核认为没必要把垃圾再塞回给你。</li></ul><p>如果你想抠细节，可以去翻 <code>net/netlink/af_netlink.c</code> 里的 <code>netlink_ack()</code> 函数，那几行代码把上面的逻辑写得清清楚楚。</p><h3 id="走到这一步" tabindex="-1">走到这一步 <a class="header-anchor" href="#走到这一步" aria-label="Permalink to &quot;走到这一步&quot;">​</a></h3><p>我们现在手里有了 <code>NETLINK_ROUTE</code> 的消息类型清单（LINK, ADDR, ROUTE...），脑子里也有了错误处理和 ACK 的模型。</p><p>这只是「说明书」。接下来我们要进入实战环节，用这些东西去操作内核里的路由表（FIB）。我们要看看，用一条 <code>RTM_NEWROUTE</code> 消息塞进一条路由，到底需要把哪些 TLV 属性像俄罗斯套娃一样塞进消息体里。</p>`,37)])])}const k=n(i,[["render",t]]);export{h as __pageData,k as default};
